mapper.select:
select d.*,c.name as category_name from dish d left join category c on d.category_id = c.id
d.status = #{dishPageQueryDTO.status}
and d.category_id = #{dishPageQueryDTO.categoryId}
and d.name like concat('%',#{dishPageQueryDTO.name},'%')
order by d.create_time desc

select d.*,c.name as category_name from dish d
left join category c on d.category_id = c.id


        d.category_id = #{categoryId}


        and d.status = #{status}


        and d.name like concat('%',#{name},'%')


order by d.create_time desc
